def is_album_available(music_library, album_name):
    return any(album['name'] == album_name for album in music_library)

# Example usage:
music_library = [
    {'name': 'Funk Upon a Rhyme', 'artist': 'Kokane', 'year': 1994},
    {'name': 'The Chronic', 'artist': 'Dr. Dre', 'year': 1992}
]

print(is_album_available(music_library, 'Funk Upon a Rhyme'))  # Output: True
